mapper.select:
SELECT sc.id, sc.student_id, sc.course_id, sc.course_name, sc.selected_time, sc.learning_status, sc.progress_percentage, sc.total_study_time, sc.last_study_time, sc.completed_time, sc.rating, sc.created_time, sc.updated_time FROM student_course sc WHERE sc.course_id = #{courseId} AND sc.learning_status != 'DROPPED'
AND sc.student_id = #{studentId}
ORDER BY sc.selected_time DESC
